document.addEventListener('DOMContentLoaded',function(){
  if(!window.Microgifter)return;
  var bundleForm=document.querySelector('[data-admin-stamp-bundle-form]');
  var bundleList=document.querySelector('[data-admin-stamp-bundle-list]');
  var bundleStatus=document.querySelector('[data-admin-stamp-bundle-status]');
  var monthlyForm=document.querySelector('[data-admin-monthly-stamps-form]');
  var monthlyStatus=document.querySelector('[data-admin-monthly-stamps-status]');
  var assignForm=document.querySelector('[data-admin-package-assignment-form]');
  var assignStatus=document.querySelector('[data-admin-package-assignment-status]');
  var assignList=document.querySelector('[data-admin-package-assignment-list]');
  var assignRefresh=document.querySelector('[data-load-package-assignments]');
  var adjustmentForm=document.querySelector('[data-admin-stamp-adjustment-form]');
  var adjustmentStatus=document.querySelector('[data-admin-stamp-adjustment-status]');
  var returnForm=document.querySelector('[data-admin-stamp-void-form]');
  var returnStatus=document.querySelector('[data-admin-stamp-void-status]');
  var renewalsForm=document.querySelector('[data-admin-monthly-renewals-form]');
  var renewalsStatus=document.querySelector('[data-admin-monthly-renewals-status]');
  var renewalsList=document.querySelector('[data-admin-monthly-renewals-list]');
  var previewButton=document.querySelector('[data-preview-renewals]');
  function esc(v){return String(v==null?'':v).replace(/[&<>'"]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'})[c];});}
  function setStatus(el,msg,type){if(window.Microgifter&&typeof Microgifter.setStatus==='function'){Microgifter.setStatus(el,msg,type);return;}if(el)el.textContent=msg||'';}
  function money(cents,currency){return String(currency||'USD')+' '+(Number(cents||0)/100).toFixed(2);}
  function idem(prefix){return prefix+'-'+Date.now()+'-'+Math.random().toString(16).slice(2);}
  function row(b){return '<tr data-bundle-row data-bundle="'+esc(JSON.stringify(b))+'"><td><strong>'+esc(b.label)+'</strong></td><td>'+esc(b.bundle_key)+'</td><td>'+Number(b.stamps||0).toLocaleString()+'</td><td>'+esc(money(b.price_cents,b.currency))+'</td><td>'+esc(b.status)+'</td><td><button class="mg-btn mg-btn-soft" type="button" data-edit-bundle>Edit</button></td></tr>';}
  function assignRow(a){return '<tr data-assignment-row data-assignment="'+esc(JSON.stringify(a))+'"><td>'+Number(a.account_user_id||0)+'</td><td><strong>'+esc(a.package_id)+'</strong></td><td>'+Number(a.monthly_stamps_included||0).toLocaleString()+'</td><td>'+esc(a.status)+'</td><td>'+esc(a.renews_at||'')+'</td><td><button class="mg-btn mg-btn-soft" type="button" data-edit-assignment>Edit</button></td></tr>';}
  function bindEdits(){if(bundleList&&bundleForm){bundleList.querySelectorAll('[data-edit-bundle]').forEach(function(btn){btn.addEventListener('click',function(){var tr=btn.closest('[data-bundle-row]');if(!tr)return;var data={};try{data=JSON.parse(tr.getAttribute('data-bundle')||'{}');}catch(e){}Object.keys(data).forEach(function(k){var el=bundleForm.elements[k==='id'?'bundle_id':k];if(el)el.value=data[k]==null?'':data[k];});setStatus(bundleStatus,'Editing '+(data.label||'Stamp bundle')+'.');});});}if(assignList&&assignForm){assignList.querySelectorAll('[data-edit-assignment]').forEach(function(btn){btn.addEventListener('click',function(){var tr=btn.closest('[data-assignment-row]');if(!tr)return;var data={};try{data=JSON.parse(tr.getAttribute('data-assignment')||'{}');}catch(e){}Object.keys(data).forEach(function(k){var el=assignForm.elements[k==='id'?'assignment_id':k];if(el)el.value=data[k]==null?'':data[k];});setStatus(assignStatus,'Editing package assignment for account '+(data.account_user_id||'')+'.');});});}}
  async function loadBundles(){if(!bundleList)return;try{var r=await Microgifter.get('/api/stamps/bundles.php');var bundles=(r.data||r).bundles||[];bundleList.innerHTML=bundles.length?bundles.map(row).join(''):'<tr><td colspan="6">No Stamp bundles found.</td></tr>';bindEdits();}catch(e){bindEdits();}}
  async function loadAssignments(){if(!assignList)return;try{var r=await Microgifter.get('/api/stamps/package-assignments.php');var items=(r.data||r).assignments||[];assignList.innerHTML=items.length?items.map(assignRow).join(''):'<tr><td colspan="6">No package assignments found.</td></tr>';bindEdits();}catch(e){assignList.innerHTML='<tr><td colspan="6">Package assignments unavailable.</td></tr>';}}
  function renewalRows(data){var items=(data.assignments||data.credited||[]);if(!renewalsList)return;if(!items.length){renewalsList.innerHTML='<tr><td colspan="5">No active package assignments found.</td></tr>';return;}renewalsList.innerHTML=items.map(function(r){return '<tr><td>'+Number(r.account_user_id||0)+'</td><td>'+esc(r.plan_id||'')+'</td><td>'+esc(r.period||data.period||'')+'</td><td>'+Number(r.monthly_stamps_included||0).toLocaleString()+'</td><td>'+esc(r.already_credited?'Already credited':(r.ledger_entry_id?'Credited':'Pending'))+'</td></tr>';}).join('');}
  async function previewRenewals(){if(!renewalsForm)return;var data=Object.fromEntries(new FormData(renewalsForm).entries());var q=[];if(data.period)q.push('period='+encodeURIComponent(data.period));if(data.limit)q.push('limit='+encodeURIComponent(data.limit));try{setStatus(renewalsStatus,'Loading renewal preview...');var r=await Microgifter.get('/api/stamps/monthly-renewals.php'+(q.length?'?'+q.join('&'):''));var payload=r.data||r;renewalRows(payload);setStatus(renewalsStatus,'Preview loaded: '+Number(payload.pending_count||0)+' pending of '+Number(payload.count||0)+'.','success');}catch(error){setStatus(renewalsStatus,error.message||'Unable to preview renewals.','error');}}
  if(bundleForm){bundleForm.addEventListener('submit',async function(ev){ev.preventDefault();var data=Object.fromEntries(new FormData(bundleForm).entries());try{setStatus(bundleStatus,'Saving Stamp bundle...');var r=await Microgifter.post('/api/stamps/bundles.php',data);setStatus(bundleStatus,r.message||'Stamp bundle saved.','success');bundleForm.reset();await loadBundles();}catch(error){setStatus(bundleStatus,error.message||'Unable to save Stamp bundle.','error');}});}
  if(assignForm){assignForm.addEventListener('submit',async function(ev){ev.preventDefault();var data=Object.fromEntries(new FormData(assignForm).entries());try{setStatus(assignStatus,'Saving package assignment...');var r=await Microgifter.post('/api/stamps/package-assignments.php',data);setStatus(assignStatus,r.message||'Package assignment saved.','success');assignForm.reset();await loadAssignments();await previewRenewals();}catch(error){setStatus(assignStatus,error.message||'Unable to save package assignment.','error');}});}
  if(adjustmentForm){adjustmentForm.addEventListener('submit',async function(ev){ev.preventDefault();var data=Object.fromEntries(new FormData(adjustmentForm).entries());data.idempotency_key=idem('admin-adjustment');try{setStatus(adjustmentStatus,'Recording Stamp adjustment...');var r=await Microgifter.post('/api/stamps/adjustment.php',data);var entry=(r.data&&r.data.entry)||{};setStatus(adjustmentStatus,(r.message||'Adjustment recorded.')+' Balance: '+(entry.balance_after==null?'updated':entry.balance_after),'success');adjustmentForm.reset();}catch(error){setStatus(adjustmentStatus,error.message||'Unable to record adjustment.','error');}});}
  if(returnForm){returnForm.addEventListener('submit',async function(ev){ev.preventDefault();var data=Object.fromEntries(new FormData(returnForm).entries());data.idempotency_key=idem('admin-return');try{setStatus(returnStatus,'Returning Stamps...');var r=await Microgifter.post('/api/stamps/void.php',data);var entry=(r.data&&r.data.entry)||{};setStatus(returnStatus,(r.message||'Stamps returned.')+' Balance: '+(entry.balance_after==null?'updated':entry.balance_after),'success');returnForm.reset();}catch(error){setStatus(returnStatus,error.message||'Unable to return Stamps.','error');}});}
  if(monthlyForm){monthlyForm.addEventListener('submit',async function(ev){ev.preventDefault();var data=Object.fromEntries(new FormData(monthlyForm).entries());try{setStatus(monthlyStatus,'Crediting monthly Stamps...');var r=await Microgifter.post('/api/stamps/monthly-credit.php',data);var entry=(r.data&&r.data.entry)||{};setStatus(monthlyStatus,(r.message||'Monthly Stamps credited.')+' Balance: '+(entry.balance_after==null?'updated':entry.balance_after),'success');}catch(error){setStatus(monthlyStatus,error.message||'Unable to credit monthly Stamps.','error');}});}
  if(previewButton){previewButton.addEventListener('click',previewRenewals);}if(assignRefresh){assignRefresh.addEventListener('click',loadAssignments);}
  if(renewalsForm){renewalsForm.addEventListener('submit',async function(ev){ev.preventDefault();var data=Object.fromEntries(new FormData(renewalsForm).entries());data.dry_run=renewalsForm.elements.dry_run&&renewalsForm.elements.dry_run.checked?1:0;try{setStatus(renewalsStatus,data.dry_run?'Previewing renewals...':'Running renewals...');var r=await Microgifter.post('/api/stamps/monthly-renewals.php',data);var payload=r.data||r;renewalRows(payload);setStatus(renewalsStatus,r.message||'Monthly renewals processed.','success');}catch(error){setStatus(renewalsStatus,error.message||'Unable to run renewals.','error');}});}
  loadBundles();loadAssignments();
});
